import sys

def solve(data: str) -> str:
    tokens = data.split()
    size = int(tokens[0])
    words = tokens[1:]
    def chunks(values: list[str], width: int):
        for index in range(0, len(values), width):
            yield values[index:index + width]
    return '|'.join(','.join(chunk) for chunk in chunks(words, size))

if __name__ == "__main__":
    print(solve(sys.stdin.read()), end="")
